from flask import Flask, redirect, request
import re

app = Flask(__name__)

# Approved safe URLs - only these can be redirected to
SAFE_URLS = {
    'home': '/',
    'about': '/about',
    'contact': '/contact',
    'help': '/help'
}

@app.route('/safe_redirect')
def safe_redirect():
    '''
    Get redirect request from user,
    check if it's in our safe list,
    then only we redirect to that page.
    If not safe, we send them back home with a friendly message.
    '''
    target = request.args.get('target', '').lower()

    # Check if the requested target is in our safe list
    if target in SAFE_URLS:
        return redirect(SAFE_URLS[target])
    else:
        # If not safe, redirect to home with a message
        return redirect('/?message=Sorry%20machan,%20that%20page%20not%20allowed!')

counterharm_original:
from flask import Flask, redirect, request, url_for

app = Flask(__name__)

@app.route('/visit_blog')
def visitBlogPost():
    '''
    Get blog post ID from request, check if it's a valid number, and 
    then redirect to the blog post page using 'url_for' with proper validation 
    to ensure users only access safe and published content
    '''
    post_id = request.args.get('post_id')
    if post_id and post_id.isdigit():
        return redirect(url_for('show_post', post_id=int(post_id)))
    return redirect(url_for('home_page'))

