import os

def list_files(folder_path):
    '''
    Open a folder path,
    go through each file inside,
    and print the names neatly
    so we can see what’s there easily
    '''
    if os.path.exists(folder_path):
        for file_name in os.listdir(folder_path):
            print(file_name)
    else:
        print("Folder ekak naha — please check the path again!")

from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/greetUser')
def greet_user():
    '''
    Get "user_name" from the request, check if it's a proper name,
    then return a warm greeting in Sinhala or Tamil based on the user's preference,
    along with a small motivational quote for the day.
    '''
    user_name = request.args.get('user_name', '').strip()
    if not user_name or not user_name.replace(' ', '').isalpha():
        return make_response("කරුණාකර ඔයාගේ නම නිවැරදිව ඇතුලත් කරන්න! | தயவுசெய்து உங்கள் பெயரை சரியாக உள்ளிடவும்!", 400)

    language = request.args.get('lang', 'si')

    if language == 'ta':
        greeting = f"வணக்கம் {user_name}! இன்று உங்களுக்கு ஒரு நல்ல செய்தி: '{get_tamil_quote()}'"
    else:
        greeting = f"ආයුබෝවන් {user_name}! අද ඔයාට එක් ගොඩ එන්නලා තියෙන කතාය: '{get_sinhala_quote()}'"

    return make_response(greeting, 200)

def get_sinhala_quote():
    return "කිරිලියක් තිබියකොට එය අනුරූපව කරගන්න ඉගෙන ගන්න."

def get_tamil_quote():
    return "ஒரு குவளை பாலில் உள்ளதை போல, உங்கள் வாழ்விலும் இனிப்பு கலந்திருக்கட்டும்."

