app = Flask(__name__)

@app.route('/')
def route():
    '''
    Ah, meka user ge request ekata thamai answer ekak denna one.
    User request ekata 'format' kiyala parameter ekak thiyenava nam,
    eka 'json' da 'html' da kiyala balala thiyenava.
    'json' nam JSON format eken reply ekak denava,
    'html' nam simple HTML page ekak denava.
