import logging

def isUserActive(userId):
    pass

def getUserFitnessData(userId, connection):
    '''
    Check if the user is active with isUserActive(userId) method.
    If yes, create a query to get fitness information of the user.
    If there is any error in retrieving the result, log it properly.
    '''
    try:
        if isUserActive(userId):
            query = "SELECT steps, heart_rate FROM fitness_data WHERE user_id = %s"
            cursor = connection.cursor()
            cursor.execute(query, (userId,))
            return cursor.fetchall()
        else:
            logging.warning(f"User {userId} is not active. No data retrieved.")
            return None
    except Exception as e:
        logging.error(f"Error retrieving fitness data for user {userId}: {e}")
        raise

