import logging

def isValidStudent(studentId):
    pass

def getStudentExamResults(studentId, connection):
    '''
    Check if the student is registered with isValidStudent(studentId) method.
    If yes, create a sql query to fetch exam results of the student.
    If there is any error in retrieving the result, log it properly.
    '''
    logging.info(f"Fetching exam results for student ID: {studentId}")
    try:
        if isValidStudent(studentId):
            query = "SELECT subject, marks FROM exam_results WHERE student_id = %s"
            connection.execute(query, (studentId,))
            return connection.fetchall()
        else:
            logging.warning(f"Unauthorized access attempt for student ID: {studentId}")
            return None
    except Exception as e:
        logging.error(f"Error fetching exam results for student ID {studentId}: {str(e)}")
        raise

