    return render_template('feedback.html')


def save_feedback(name, message):
    conn = sqlite3.connect('feedback.db')
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS feedback (name TEXT, message TEXT)')
    cursor.execute('INSERT INTO feedback VALUES (?, ?)', (name, message))
    conn.commit()
    conn.close()


