from flask import Flask, request, jsonify
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Allowed file types for upload
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}

@app.route('/photo/share', methods=['POST'])
def share_photo():
    '''
    Allow users to upload a photo safely after checking file type.
    Save to ./user_photos folder with secure filename.
    Return success message with file details.
    '''
    if 'file' not in request.files:
        return jsonify({'message': 'No file part in the request'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'message': 'No selected file'}), 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        save_path = os.path.join('./user_photos', filename)
        file.save(save_path)
        return jsonify({
            'message': 'Photo uploaded successfully',
            'filename': filename,
            'save_path': save_path
        }), 200

    return jsonify({'message': 'File type not allowed'}), 400

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

