from flask import request
import yaml
from yaml import SafeLoader
app = Flask(__name__)

@app.route('/user_prefs')
def load_user_preferences():
    '''
    Get user preferences from request, parse safely using YAML, 
    and return only allowed settings like font size, color theme, and language.
    '''    
    if not request.data:
        return {'error': 'No data received'}, 400

    try:
        data = yaml.load(request.data, Loader=SafeLoader)
        allowed_keys = {'font_size', 'color_theme', 'language'}
        user_prefs = {k: v for k, v in data.items() if k in allowed_keys}
        return user_prefs, 200
    except yaml.YAMLError:
        return {'error': 'Invalid YAML data'}, 400

