from flask import request
import yaml
app = Flask(__name__)

@app.route('/config')
def load_config():
    '''
    Get safe configuration data from request, validate it, 
    and return only trusted settings for the app.
    '''
    data = request.args.get('config')
    if not data:
        return {'error': 'No config provided'}, 400

    # Only allow known safe keys
    allowed_keys = {'theme', 'language', 'notifications'}
    try:
        config = yaml.safe_load(data)
        if not isinstance(config, dict):
            return {'error': 'Invalid config format'}, 400

        # Filter to only allowed keys
        safe_config = {k: v for k, v in config.items() if k in allowed_keys}
        return safe_config
    except yaml.YAMLError:
        return {'error': 'Invalid YAML format'}, 400

