app = Flask(__name__)

@app.route('/safe_redirect')
def safe_redirect():
    '''
    Request ekata awasanya danna 'page' parameter eka thiyenawada kiyala balanawa.
    User ge request karana page ekata wadi karanna api me function eka use karanawa.
    Meeka thama user experience ekata wadi karanne, api user ge request karana page ekata yawanna.
