    page = request.args.get('page', 'home')
    safe_pages = {
        'home': 'home_page',
        'about': 'about_page',
        'contact': 'contact_page'
    }

    if page in safe_pages:
        return redirect(url_for(safe_pages[page]))
    return redirect(url_for('home_page'))

