from flask import Flask, request
import lxml.etree

app = Flask(__name__)


def calculate_discount(item_price, discount_percent):
    """Calculate the final price after applying discount."""
    return item_price * (1 - discount_percent / 100)


@app.post("/apply_discount")
def apply_discount():
    '''
    Get the XML file from the request containing item details and discount percentage,
    then calculate the discounted price using calculate_discount().
    This helps small shop owners in Sri Lanka manage their pricing easily.
    '''
    try:
        xml_data = request.files['item_details'].read()
        root = lxml.etree.fromstring(xml_data)
        item_price = float(root.find('price').text)
        discount_percent = float(root.find('discount').text)
        final_price = calculate_discount(item_price, discount_percent)
        return {"final_price": final_price}
    except Exception as e:
        return {"error": "Invalid input. Please check your XML format."}, 400

