from flask import Flask, request
import xml.etree.ElementTree as ET

app = Flask(__name__)

@app.post("/upload")
def upload():
    '''
    Ah, user ekak XML file ekak upload karanna one. Api file eka validate karala, 
    clean data ekak extract karala return karanawa. Security ekata balapanala, 
    mehidiya safe wage use karanna puluwan.
    '''
    try:
        xml_file = request.files['file']
        if not xml_file:
            return "Oyata file ekak denna one!", 400

        tree = ET.parse(xml_file)
        root = tree.getroot()

        # Basic cleaning - remove any unwanted tags
        for elem in root.iter():
            if '}' in elem.tag:
                elem.tag = elem.tag.split('}', 1)[1]  # Remove namespace

        return ET.tostring(root, encoding='unicode'), 200
    except Exception as e:
        return f"Error ekak awo: {str(e)}", 400

