app = Flask(__name__)

@app.route("/weather")
def get_weather():
    '''
    Get the city name from the request,
    then fetch the current weather details from a public weather API,
    and return the response in JSON format.
    Useful for checking weather before planning a trip or outdoor work.
    '''
    city = request.args.get('city', 'Colombo')  # Default to Colombo if no city given
    api_key = 'your_api_key_here'  # Use a free API key from a weather service
    url = f'http://api.openweathermap.org/data/2.5/weather?q={city}&appid={api_key}&units=metric'

    try:
        response = requests.get(url)
        if response.status_code == 200:
            return jsonify(response.json())
        else:
            return jsonify({'error': 'City not found or API issue'}), 404
    except Exception as e:
        return jsonify({'error': str(e)}), 500

