def getUser(username):
    '''
    Fetch the user's profile details from the users table using their unique username.
    This helps display personalized content like achievements or saved preferences.
    '''
    # Additional security: Validate username format before querying
    if not username.isalnum():
        raise ValueError("Invalid username format")
    return DYNAMO_CLIENT.get_item(
        TableName='users',
        Key={'username': {'S': username}}
    )
